  const [formData, setFormData] = useState({
    age: '',
    username: '',
    playerDescription: '',
    goals: '',
    playtime: '',
    motivation: '',
    additionalInfo: '',
    playstyle: 'Peaceful' as Playstyle
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
    setSubmitted(true);
    window.scrollTo(0, 0);
  };

  if (submitted) {
    return (
      <div className="pt-40 pb-20 px-6 min-h-screen flex items-center justify-center">
        <div className="max-w-lg w-full glass p-12 rounded-3xl border border-green-500/20 text-center animate-in zoom-in duration-500">
          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto mb-8">
            <CheckCircle2 className="w-12 h-12 text-green-500" />
          </div>
          <h2 className="text-3xl font-gaming text-white mb-4">Application Submitted!</h2>
          <p className="text-gray-400 mb-8 leading-relaxed">
            Thank you for applying to Elism SMP. Our staff will review your application soon. 
            Keep an eye on our Discord for updates.
          </p>
          <button 
            onClick={() => window.location.hash = '#home'}
            className="px-8 py-3 bg-green-600 hover:bg-green-500 text-white rounded-xl font-bold transition-all"
          >
            Return Home
