import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Home } from './pages/Home';
import { ApplicationPage } from './pages/Application';
import { AdminPage } from './pages/Admin';
import { Application } from './types';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState('home');
  const [applications, setApplications] = useState<Application[]>([]);
  const [isAdminMode, setIsAdminMode] = useState(false);

  // Load from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem('elism_applications');
    if (saved) {
      setApplications(JSON.parse(saved));
    }

    const handleHashChange = () => {
      const hash = window.location.hash.replace('#', '') || 'home';
      setCurrentPage(hash);
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange();

    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  // Save to localStorage whenever applications change
  useEffect(() => {
    localStorage.setItem('elism_applications', JSON.stringify(applications));
  }, [applications]);

  const handleNavigate = (page: string) => {
    window.location.hash = page;
  };

  const handleApply = (newAppData: Omit<Application, 'id' | 'status' | 'submittedAt'>) => {
    const newApp: Application = {
      ...newAppData,
      id: Math.random().toString(36).substring(2, 9),
      status: 'Pending',
      submittedAt: Date.now()
    };
    setApplications(prev => [...prev, newApp]);
  };

  const updateAppStatus = (id: string, status: 'Accepted' | 'Denied') => {
    setApplications(prev => prev.map(app => app.id === id ? { ...app, status } : app));
  };

  const deleteApp = (id: string) => {
    if (confirm('Are you sure you want to delete this application?')) {
      setApplications(prev => prev.filter(app => app.id !== id));
    }
  };

  const handleAdminAuth = () => {
    const code = prompt('Enter admin access code:');
    if (code === '654321') {
      setIsAdminMode(true);
      handleNavigate('admin');
    } else {
      alert('Incorrect code.');
    }
  };

  return (
    <div className="min-h-screen">
      <Navbar currentPage={currentPage} onNavigate={handleNavigate} />

      <main>
        {currentPage === 'home' && <Home onNavigate={handleNavigate} />}
        {currentPage === 'application' && <ApplicationPage onSubmit={handleApply} />}
        {currentPage === 'admin' && (
          isAdminMode ? (
            <AdminPage 
              applications={applications} 
              onUpdateStatus={updateAppStatus} 
              onDelete={deleteApp} 
            />
          ) : (
            <div className="pt-40 text-center">
              <h1 className="text-2xl text-white">Access Denied</h1>
              <button onClick={() => handleNavigate('home')} className="text-orange-500 mt-4 underline">Go Home</button>
            </div>
          )
        )}
      </main>

      <footer className="py-12 border-t border-white/5 bg-[#080808] px-6">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-2 opacity-50">
            <span className="font-gaming text-white">ELISM SMP</span>
            <span className="text-gray-600">© 2024. All rights reserved.</span>
          </div>

          <div className="flex items-center gap-8 text-sm text-gray-500">
            <a href="#" className="hover:text-white transition-colors">Privacy</a>
            <a href="#" className="hover:text-white transition-colors">Terms</a>
            <a href="#" className="hover:text-white transition-colors">Discord</a>
          </div>

          {/* Hidden Admin Entry */}
          <div 
            className="w-1 h-1 bg-white/5 cursor-pointer hover:bg-orange-500/20 rounded-full transition-colors"
            title="Admin Login"
            onClick={handleAdminAuth}
          />
        </div>
      </footer>
    </div>
  );
};

export default App;

